Add comprehensive testing pattern for validation-based features:

**Validation Test Structure:**
```typescript
describe('validate<X>', () => {
  it('throws for negative value', () => {
    expect(() => validate({ field: -0.1 })).toThrow('field is negative');
  });
  it('throws for value > 1', () => {
    expect(() => validate({ field: 1.01 })).toThrow('field exceeds 1');
  });
  it('throws for NaN', () => {
    expect(() => validate({ field: NaN })).toThrow('field is NaN');
  });
  it('accepts valid boundaries', () => {
    expect(() => validate({ field: 0 })).not.toThrow();
    expect(() => validate({ field: 1 })).not.toThrow();
  });
});

describe('backward compatibility', () => {
  it('produces same result without parameter', () => {
    const resultWithout = fn(input);
    const resultWithEmpty = fn(input, { param: {} });
    expect(resultWithEmpty).toEqual(resultWithout);
  });
});

describe('per-component override', () => {
  it('component A affects only component A score', () => {
    const high = fn(input, { weights: { a: 0.8 } });
    const low = fn(input, { weights: { a: 0.1 } });
    expect(high.score).toBeGreaterThan(low.score);
  });
});
```

**Integration Testing Pattern:**
```typescript
// Use fake timers for time-based features
beforeEach(() => {
  vi.useFakeTimers();
  vi.setSystemTime(new Date('2024-06-15'));
});
afterEach(() => vi.useRealTimers());

it('applies weights before recency/quality', () => {
  const result = fn(input, {
    weights: { skills: 0.6, location: 0.2, rate: 0.1, role: 0.1 },
    matchDecisions: [{ status: 'approved', reviewedAt: now }]
  });
  expect(result.reasoning).toContain('Recente match');
  expect(result.reasoning).toContain('Hoge goedkeuring');
});
```

**Critical Patterns to Document:**
- Boundary testing (0, 1, epsilon below/above)
- Invalid value handling (negative, NaN, undefined)
- Backward compatibility verification
- Partial vs full override scenarios
- Integration with existing factors (recency, quality)
